const normalizedData = $('Normalize Input').item.json;
const rawCampaign = $input.item.json.choices[0].message.content;

// Clean markdown
const cleanCampaign = rawCampaign.replace(/```json/g, '').replace(/```/g, '').trim();

// Fix common JSON errors from model output
const fixedCampaign = cleanCampaign
  .replace(/,\s*}/g, '}')
  .replace(/,\s*]/g, ']')
  .replace(/("[^"]*":\s*"[^"]*)[^"]*("[^"]*"\s*[,}])/g, '$1$2');

// Parse JSON
let campaign;
try {
  campaign = JSON.parse(cleanCampaign);
} catch(e1) {
  try {
    campaign = JSON.parse(fixedCampaign);
  } catch(e2) {
    // Extract fields manually using regex as last resort
    const getName = cleanCampaign.match(/"campaign_name"\s*:\s*"([^"]+)"/);
    const getSummary = cleanCampaign.match(/"executive_summary"\s*:\s*"([^"]+)"/);
    const getScore = cleanCampaign.match(/"confidence_score"\s*:\s*(\d+)/);
    campaign = {
      campaign_name: getName ? getName[1] : 'Campaign Brief',
      executive_summary: getSummary ? getSummary[1] : 'Campaign brief generated successfully.',
      confidence_score: getScore ? getScore[1] : 'N/A',
      launch_timeline: {
        phase1: { duration: 'Week 1-2', focus: 'Awareness' },
        phase2: { duration: 'Week 3-5', focus: 'Conversion' },
        phase3: { duration: 'Week 6-8', focus: 'Retention' }
      },
      kpis: [],
      launch_checklist: [],
      channel_strategy: {}
    };
  }
}

// Safely extract fields
const campaignName = campaign.campaign_name || 'Campaign Brief';
const execSummary = campaign.executive_summary || 'Campaign brief generated.';
const confidenceScore = campaign.confidence_score || 'N/A';

const phase1 = campaign.launch_timeline?.phase1;
const phase2 = campaign.launch_timeline?.phase2;
const phase3 = campaign.launch_timeline?.phase3;

const kpis = Array.isArray(campaign.kpis) ? campaign.kpis : [];
const checklist = Array.isArray(campaign.launch_checklist) ? campaign.launch_checklist : [];
const channels = campaign.channel_strategy ? Object.keys(campaign.channel_strategy) : [];

const messageContent = `🎉 PIPELINE COMPLETE - AI E-COMMERCE LAUNCH COMMAND\n\n🚀 Campaign: ${campaignName}\n📦 Product: ${normalizedData.product_name}\n👥 Audience: ${normalizedData.target_audience}\n\n📊 Pipeline Summary:\n✅ Research Agent - Market analysis complete\n✅ Content Agent - Copy and emails generated\n✅ Review Agent - Score ${normalizedData.overall_score}/10 Approved\n✅ Campaign Agent - Brief assembled\n\n💼 Executive Summary:\n${execSummary}\n\n📅 Launch Timeline:\n- Phase 1: ${phase1?.duration || 'Week 1-2'} - ${phase1?.focus || 'Awareness'}\n- Phase 2: ${phase2?.duration || 'Week 3-5'} - ${phase2?.focus || 'Conversion'}\n- Phase 3: ${phase3?.duration || 'Week 6-8'} - ${phase3?.focus || 'Retention'}\n\n💰 Recommended Channels:\n${channels.length > 0 ? channels.map(ch => `- ${ch}: ${campaign.channel_strategy[ch]?.tactic || ''} (ROAS: ${campaign.channel_strategy[ch]?.expected_roas || 'N/A'})`).join('\n') : '- Multi-channel strategy'}\n\n📊 KPIs:\n${kpis.length > 0 ? kpis.map(k => `- ${k.metric}: ${k.target}`).join('\n') : '- See full brief for KPIs'}\n\n✅ Launch Checklist:\n${checklist.length > 0 ? checklist.map(item => `- ${item}`).join('\n') : '- See full brief for checklist'}\n\n💡 Confidence Score: ${confidenceScore}/10`;

return [{
  json: {
    product_name: normalizedData.product_name,
    campaign_brief: cleanCampaign,
    band_message: messageContent,
    chat_id: normalizedData.chat_id,
    band_api_key: '[REDACTED_BAND_API_KEY]'
  }
}];

